public async Task<bool> PurchaseTickets(int eventId, int quantity)
{
    using (var context = new EventBookingSystemContext())
    {
        var @event = await context.Events.FindAsync(eventId);
        
        if (@event == null || @event.AvailableSeats < quantity) 
            return false; // Not enough seats or event not found
            
        @event.AvailableSeats -= quantity;
        await context.SaveChangesAsync();
    }
    
    return true;
}